const payment = $input.first().json.payload.payment.entity;
const amount = (payment.amount / 100).toFixed(2);
const message = `✅ *Payment Received!*\n\n` +
  `💰 Amount: ₹${amount}\n` +
  `📌 Order ID: ${payment.order_id || 'N/A'}\n` +
  `👤 Customer: ${payment.email || payment.contact || 'Unknown'}\n` +
  `💳 Method: ${payment.method}\n` +
  `🕑 Time: ${new Date(payment.created_at * 1000).toLocaleString('en-IN', {timeZone: 'Asia/Kolkata'})}\n` +
  `🆔 Payment ID: ${payment.id}`;
return [{ json: { message } }];
